1	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
2	
3	function validateItemTypes(items: any[]): void {
4	  for (const item of items) {
5	    if (!KNOWN_TYPES.includes(item.type)) {
6	      throw new Error(`Unknown item type: ${item.type}`);
7	    }
8	  }
9	}
10	
11	const PROCESSING_FEE = 5;
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	};
18	
19	function basePremium(item: any): number {
20	  return BASE_PREMIUMS[item.type] ?? 0;
21	}
22	
23	export function claimOffice(input: any): unknown {
24	  const results = [];
25	  for (const step of input.steps) {
26	    validateItemTypes(step.items);
27	    let premium = PROCESSING_FEE;
28	    for (const item of step.items) {
29	      premium += basePremium(item);
30	    }
31	    results.push({ premium });
32	  }
33	  return { results };
34	}
